SELECT d.*, b.branch_name, c.client_name
FROM devices d
LEFT JOIN branches b ON d.branch_id = b.id
LEFT JOIN clients c ON b.client_id = c.id
WHERE 1=1

    AND d.branch_id = #{branchId}


    AND b.client_id = #{clientId}


    AND d.status = #{status}


    AND (d.device_code LIKE CONCAT('%', #{keyword}, '%') OR d.device_name LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY d.id DESC

