SELECT COUNT(*) FROM devices d LEFT JOIN branches b ON d.branch_id = b.id WHERE 1=1
AND d.branch_id = #{branchId}
AND d.status = #{status}
AND (d.device_code LIKE CONCAT('%', #{keyword}, '%') OR d.device_name LIKE CONCAT('%', #{keyword}, '%'))

SELECT COUNT(*) as total_count, COUNT(CASE WHEN status = '运行' THEN 1 END) as running_count, COUNT(CASE WHEN status = '停用' THEN 1 END) as stopped_count, COUNT(CASE WHEN status = '故障' THEN 1 END) as fault_count FROM devices WHERE 1=1
AND branch_id = #{branchId}
AND branch_id IN (SELECT id FROM branches WHERE client_id = #{clientId})

